const L=['A','B','C','D'];
const COLS={hist:{cls:'hc',lbl:'История <b>КЗ</b>',name:'История КЗ'},info:{cls:'ic',lbl:'Инфо<b>рматика</b>',name:'Информатика'},rus:{cls:'rc',lbl:'Русский <b>язык</b>',name:'Русский язык'},kaz:{cls:'kc',lbl:'Қазақ <b>тілі</b>',name:'Қазақ тілі'}};
const mk=d=>d.map(r=>({q:r[0],o:[r[1],r[2],r[3],r[4]],a:r[5]}));
let BH=null,BI=null,BR=null,BK=null;
const getB=s=>s==='hist'?(BH||(BH=mk(RH))):s==='info'?(BI||(BI=mk(RI))):s==='rus'?(BR||(BR=mk(RR))):(BK||(BK=mk(RK)));
const W={hist:new Set(),info:new Set(),rus:new Set(),kaz:new Set()};
let sub='hist',qs=[],cur=0,sc=0,ans=[],shuf=[];
const shuffle=a=>[...a].sort(()=>Math.random()-.5);
function show(id,lbl){document.querySelectorAll('.screen').forEach(s=>s.classList.remove('on'));document.getElementById(id).classList.add('on');document.getElementById('chip').textContent=lbl||'';}
function goMode(s){sub=s;updW();show('s-mode-'+s,COLS[s].name);}
function updW(){document.getElementById('wb-h').textContent=W.hist.size;document.getElementById('wb-i').textContent=W.info.size;document.getElementById('wb-r').textContent=W.rus.size;document.getElementById('wb-k').textContent=W.kaz.size;}
function launch(s,n,mode){
  sub=s;const b=getB(s),ws=W[s];let pool;
  if(mode==='all')pool=shuffle(b);
  else if(mode==='w'){if(!ws.size){toast('Нет ошибок! Сначала пройди тест.');return;}pool=shuffle(b.filter((_,i)=>ws.has(i)));}
  else pool=shuffle(b).slice(0,n);
  qs=pool;cur=0;sc=0;ans=[];
  const c=COLS[s],ic=s!=='hist';
  document.getElementById('qsl').innerHTML=c.lbl;
  document.getElementById('qsl').className='qsubj'+(s==='info'?' ic':s==='rus'?' rc':s==='kaz'?' kc':'');
  document.getElementById('pb').className='pb'+(s==='info'?' ic':s==='rus'?' rc':s==='kaz'?' kc':'');
  document.getElementById('nb').className='nbtn '+c.cls;
  document.getElementById('rbtn').className='nbtn '+c.cls;
  show('s-quiz',c.name);showQ();
}
function showQ(){
  const q=qs[cur],tot=qs.length;
  document.getElementById('qn').textContent='ВОПРОС '+(cur+1);
  document.getElementById('qt').textContent=q.q;
  document.getElementById('qnl').textContent=(cur+1)+'/'+tot;
  document.getElementById('pb').style.width=(cur/tot*100)+'%';
  document.getElementById('nb').style.display='none';
  shuf=[0,1,2,3].sort(()=>Math.random()-.5);
  document.getElementById('opts').innerHTML=shuf.map((oi,pos)=>
    '<div class="opt" id="op'+pos+'" onclick="pick('+pos+')"><div class="ltr">'+L[pos]+'</div><span>'+q.o[oi]+'</span><span class="oc"></span></div>'
  ).join('');
}
function pick(pos){
  const q=qs[cur],c=q.a,cho=shuf[pos],cp=shuf.indexOf(c);
  document.querySelectorAll('.opt').forEach(o=>{o.classList.add('dis');o.onclick=null;});
  document.getElementById('op'+cp).classList.add('ok');
  document.getElementById('op'+cp).querySelector('.oc').textContent='✓';
  const b=getB(sub),ws=W[sub],oi=b.indexOf(q);
  if(cho===c){sc++;ws.delete(oi);ans.push({q:q.q,chosen:q.o[cho],correct:q.o[c],ok:true});}
  else{document.getElementById('op'+pos).classList.add('no');document.getElementById('op'+pos).querySelector('.oc').textContent='✕';ws.add(oi);ans.push({q:q.q,chosen:q.o[cho],correct:q.o[c],ok:false});}
  updW();
  const nb=document.getElementById('nb');nb.style.display='flex';nb.textContent=cur<qs.length-1?'Следующий →':'Результаты →';
}
function nextQ(){cur++;if(cur>=qs.length){showRes();return;}showQ();}
function showRes(){
  show('s-res','Результаты');
  const tot=qs.length,pct=Math.round(sc/tot*100);
  document.getElementById('rp').textContent=pct+'%';
  document.getElementById('sok').textContent=sc;
  document.getElementById('sno').textContent=tot-sc;
  document.getElementById('stot').textContent=tot;
  const ring=document.getElementById('rc');
  setTimeout(()=>{ring.style.strokeDashoffset=326.73*(1-pct/100);ring.style.stroke=pct>=75?'#34d399':pct>=50?'#fbbf24':'#f87171';},80);
  const msgs=[[90,'🏆 Отлично!','Ты готов к сессии!'],[70,'👍 Хорошо!','Повтори ошибки!'],[50,'📚 Неплохо','Стоит повторить материал.'],[0,'😅 Учи больше!','Не сдавайся!']];
  const [,t,tx]=msgs.find(([n])=>pct>=n);
  document.getElementById('rtl').textContent=t;document.getElementById('rtx').textContent=tx;
  const wrongs=ans.filter(a=>!a.ok);
  document.getElementById('rl').innerHTML=wrongs.length
    ?wrongs.map((a,i)=>'<div class="ritem"><div class="rq">'+(i+1)+'. '+a.q+'</div><div class="rrow"><div class="ra rw">'+a.chosen+'</div><div class="ra rc2">✓ '+a.correct+'</div></div></div>').join('')
    :'<div style="text-align:center;color:#34d399;padding:18px;font-size:13px">🎉 Все ответы верны!</div>';
}
